const raw = $input.first().json;
let text = '';
if (raw.content && raw.content.parts) {
  text = raw.content.parts[0].text;
} else if (typeof raw === 'string') {
  text = raw;
} else if (raw.text) {
  text = raw.text;
} else {
  text = JSON.stringify(raw);
}

/**
 * Gemini JSON 출력 정리
 * 1. 코드블록 제거
 * 2. JSON 객체 추출 (첫 { ~ 마지막 })
 * 3. 문자열 내 제어문자(줄바꿈, 탭 등) → 공백 변환
 * 4. 트레일링 콤마 제거
 */
function cleanGeminiJson(raw) {
  // 코드블록 제거
  let s = raw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

  // JSON 객체 추출 (첫 { ~ 마지막 })
  const first = s.indexOf('{');
  const last = s.lastIndexOf('}');
  if (first !== -1 && last > first) {
    s = s.substring(first, last + 1);
  }

  // 문자열 내 제어문자 처리 (stateful char-by-char parser)
  // JSON 규격: 문자열 안의 \n, \t, \r 등은 반드시 이스케이프 필요
  // Gemini가 이스케이프 없이 출력하는 경우 → 공백으로 치환
  let result = '';
  let inStr = false;
  let esc = false;
  for (let i = 0; i < s.length; i++) {
    const c = s[i];
    if (esc) { result += c; esc = false; continue; }
    if (c === '\\' && inStr) { result += c; esc = true; continue; }
    if (c === '"') { inStr = !inStr; result += c; continue; }
    if (inStr) {
      // 줄바꿈, 캐리지리턴 → 공백
      if (c === '\n' || c === '\r') { result += ' '; continue; }
      // 탭 → 공백
      if (c === '\t') { result += ' '; continue; }
      // 기타 제어문자 (0x00~0x1F) 제거
      if (c.charCodeAt(0) < 0x20) { continue; }
    }
    result += c;
  }

  // 트레일링 콤마 제거: ,} 또는 ,]
  result = result.replace(/,(\s*[}\]])/g, '$1');

  return result;
}

let cleanText = cleanGeminiJson(text);
let data;

try {
  data = JSON.parse(cleanText);
} catch (e1) {
  // 2차 시도: 유니코드 따옴표 → 일반 따옴표, BOM 제거
  try {
    let fixed = cleanText
      .replace(/[\u201C\u201D\u201E\u201F\u2033\u2036]/g, '"')
      .replace(/[\u2018\u2019\u201A\u201B\u2032\u2035]/g, "'")
      .replace(/^\uFEFF/, '');
    data = JSON.parse(fixed);
  } catch (e2) {
    // 에러 위치 주변 텍스트 포함하여 디버그
    const posMatch = e1.message.match(/position (\d+)/);
    const pos = posMatch ? parseInt(posMatch[1]) : 0;
    const start = Math.max(0, pos - 80);
    const end = Math.min(cleanText.length, pos + 80);
    const around = cleanText.substring(start, end);
    const pointer = ' '.repeat(Math.min(pos - start, 80)) + '^^^';
    throw new Error(
      `JSON 파싱 실패: ${e1.message}\n` +
      `--- 에러 위치(${pos}) 주변 ---\n` +
      `${around}\n${pointer}\n` +
      `--- 전체 길이: ${cleanText.length}자 ---\n` +
      `처음 300자: ${cleanText.substring(0, 300)}`
    );
  }
}

if (!data.scenes || data.scenes.length < 5) {
  throw new Error('scenes must have at least 5 items, got: ' + (data.scenes?.length || 0));
}

// visual_type, meme_mood 검증 및 기본값 처리
const VALID_MOODS = ['thinking', 'excited', 'shocked', 'sad', 'angry', 'cool', 'celebrating'];

data.scenes = data.scenes.map((scene, idx) => {
  // visual_type이 없으면 위치 기반 기본값 (매 3번째 = meme)
  if (!scene.visual_type || !['image', 'meme'].includes(scene.visual_type)) {
    scene.visual_type = ((idx + 1) % 3 === 0) ? 'meme' : 'image';
  }

  // meme인데 meme_mood가 없으면 기본값
  if (scene.visual_type === 'meme') {
    if (!scene.meme_mood || !VALID_MOODS.includes(scene.meme_mood)) {
      scene.meme_mood = VALID_MOODS[idx % VALID_MOODS.length];
    }
    scene.image_prompt = scene.image_prompt || '';
    scene.keyword = scene.keyword || '';
  } else {
    scene.meme_mood = '';
    if (!scene.keyword) {
      scene.keyword = scene.image_prompt?.split(',')[0] || 'abstract background';
    }
  }

  return scene;
});

const memeCount = data.scenes.filter(s => s.visual_type === 'meme').length;
const imageCount = data.scenes.filter(s => s.visual_type === 'image').length;

return [{
  json: {
    hook_title: data.hook_title,
    scenes: data.scenes,
    Subject: data.Subject,
    Caption: data.Caption,
    Comment: data.Comment,
    fullDialogue: data.scenes.map(s => s.dialogue).join(' '),
    segmentCount: data.scenes.length,
    memeCount,
    imageCount,
    Status: '생성 중',
    generatedAt: new Date().toISOString(),
    row_number: $('주제 파싱').first().json.row_number
  }
}];

const data = $('콘텐츠 파싱').first().json;
const scenes = data.scenes || [];

return scenes.map((scene, i) => ({
  json: {
    index: i,
    dialogue: scene.dialogue,
    dialogue_tts: scene.dialogue.replace(/<em>/g, '').replace(/<\/em>/g, '').replace(/<y>/g, '').replace(/<\/y>/g, ''),
    image_prompt: scene.image_prompt,
    keyword: scene.keyword || scene.image_prompt?.split(',')[0] || 'abstract background',
    visual_type: scene.visual_type || 'image',
    meme_mood: scene.meme_mood || '',
  }
}));

const items = $input.all();

return items.map(item => {
  const audioUrl = item.json.audio_url;
  const durationSec = item.json.duration_sec;

  if (!audioUrl) {
    throw new Error('TTS 응답에 audio_url이 없습니다: ' + JSON.stringify(item.json));
  }

  return {
    json: {
      audio_url: audioUrl,
      duration_sec: durationSec,
      ...item.json
    }
  };
});

// NCA 꿀팁 숏츠 v4: BGM + 효과음 수정 + 자막 정리
const hookTitle = $('콘텐츠 파싱').first().json.hook_title;
const segmentCount = $('콘텐츠 파싱').first().json.segmentCount;

const hookClean = hookTitle.replace(/<y>/g, '').replace(/<\/y>/g, '').replace(/<em>/g, '').replace(/<\/em>/g, '');

const BGM_URL = 'http://76.13.182.180:9000/audio/bgm_25sec.mp3';
const SFX_WHOOSH = 'http://76.13.182.180:9000/audio/sfx_whoosh1.mp3';
const SFX_POP = 'http://76.13.182.180:9000/audio/sfx_pop_user.mp3';
const SFX_DING = 'http://76.13.182.180:9000/audio/sfx_ding1.mp3';
const SFX_DING2 = 'http://76.13.182.180:9000/audio/sfx_ding2.mp3';
const SFX_PPOOK = 'http://76.13.182.180:9000/audio/sfx_ppook.wav';
const SFX_WOW = 'http://76.13.182.180:9000/audio/sfx_wow.wav';

function pickSfx(seg, nextSeg) {
  if (nextSeg && nextSeg.visualType === 'meme') return 'ppook';
  if (nextSeg && /\d/.test(nextSeg.dialogueText)) return 'ding';
  return 'whoosh';
}

const SFX_MAP = { whoosh: SFX_WHOOSH, pop: SFX_POP, ding: SFX_DING, ding2: SFX_DING2, ppook: SFX_PPOOK, wow: SFX_WOW };

function getEmphasisSfx(dialogueText) {
  if (!dialogueText || !dialogueText.includes('<em>')) return null;
  if (/\d/.test(dialogueText)) return 'ding2';
  return 'pop';
}

function escapeDrawtext(text) {
  if (!text) return '';
  return text
    .replace(/\\/g, '\\\\')
    .replace(/'/g, '\u2019')
    // %는 expansion=none으로 처리
    .replace(/"/g, '\u201D')
    .replace(/:/g, '\\:')
    .replace(/;/g, '\\;')
    .replace(/,/g, '\\,')
    .replace(/\[/g, '\\[')
    .replace(/\]/g, '\\]')
    .replace(/\n/g, ' ');
}

function wrapSubtitle(text, maxLen) {
  if (text.length <= maxLen) return text;
  let lines = [];
  let current = '';
  for (const ch of text) {
    current += ch;
    if (current.length >= maxLen) {
      lines.push(current);
      current = '';
    }
  }
  if (current) lines.push(current);
  return lines.join('\n');
}

let segments = [];
let currentStart = 0;

for (let i = 0; i < segmentCount; i++) {
  const ttsResult = $('TTS 결과 처리').all()[i]?.json;
  const audioUrl = ttsResult?.audio_url || '';
  const duration = ttsResult?.duration_sec || 3;

  const imageResult = $('이미지 URL 추출').all()[i]?.json;
  const imageUrl = imageResult?.images?.[0]?.url || '';
  const isVideo = imageResult?.is_video || false;
  const visualType = imageResult?.visual_type || 'image';

  const dialogueText = $('세그먼트 분리').all()[i]?.json?.dialogue || '';

  if (!imageUrl) {
    throw new Error(`세그먼트 ${i+1} 미디어 URL 없음`);
  }

  segments.push({
    index: i + 1,
    imageUrl, audioUrl, duration,
    start: currentStart,
    dialogueText,
    isVideo,
    visualType,
  });
  currentStart += duration;
}

const totalDuration = currentStart;

let inputs = [];
let inputIndex = 0;

// ── 미디어 입력 ──
const mediaInputs = [];
for (const seg of segments) {
  if (seg.isVideo) {
    inputs.push({
      file_url: seg.imageUrl,
      options: [{ option: "-stream_loop", argument: "-1" }]
    });
  } else {
    inputs.push({
      file_url: seg.imageUrl,
      options: [
        { option: "-loop", argument: "1" },
        { option: "-framerate", argument: "30" },
        { option: "-t", argument: String(seg.duration) }
      ]
    });
  }
  mediaInputs.push({ idx: inputIndex, isVideo: seg.isVideo, duration: seg.duration });
  inputIndex++;
}

// ── TTS 오디오 입력 ──
const audioInputs = [];
const audioSegmentMap = [];
for (let i = 0; i < segments.length; i++) {
  if (segments[i].audioUrl) {
    inputs.push({ file_url: segments[i].audioUrl, options: [] });
    audioInputs.push(inputIndex);
    audioSegmentMap.push(i);
    inputIndex++;
  }
}

// ── BGM 입력 ──
const bgmIdx = inputIndex;
inputs.push({
  file_url: BGM_URL,
  options: [{ option: "-stream_loop", argument: "-1" }]
});
inputIndex++;

// ── 효과음 입력 (전환 + 강조 포인트) ──
const sfxInputs = [];

// 장면 전환 효과음
for (let i = 0; i < segments.length - 1; i++) {
  const sfxType = pickSfx(segments[i], segments[i + 1]);
  const sfxUrl = SFX_MAP[sfxType];
  inputs.push({ file_url: sfxUrl, options: [] });
  sfxInputs.push({ idx: inputIndex, type: sfxType, timeMs: Math.round(segments[i + 1].start * 1000) });
  inputIndex++;
}

// 강조(<em>) 포인트 효과음
for (const seg of segments) {
  const emSfx = getEmphasisSfx(seg.dialogueText);
  if (emSfx) {
    const sfxUrl = SFX_MAP[emSfx];
    inputs.push({ file_url: sfxUrl, options: [] });
    sfxInputs.push({ idx: inputIndex, type: emSfx, timeMs: Math.round((seg.start + 0.3) * 1000) });
    inputIndex++;
  }
}

// ══════ FILTER COMPLEX ══════
let filterParts = [];

// ── 비디오 처리 ──
for (let i = 0; i < segments.length; i++) {
  const m = mediaInputs[i];
  if (m.isVideo) {
    filterParts.push(
      `[${m.idx}:v]trim=duration=${m.duration},setpts=PTS-STARTPTS,` +
      `scale=1080:1920:force_original_aspect_ratio=decrease,` +
      `pad=1080:1920:(ow-iw)/2:(oh-ih)/2:black,` +
      `setsar=1,fps=30[v${i}]`
    );
  } else {
    filterParts.push(
      `[${m.idx}:v]scale=1080:1920:force_original_aspect_ratio=decrease,` +
      `pad=1080:1920:(ow-iw)/2:(oh-ih)/2:black,` +
      `setsar=1,fps=30[v${i}]`
    );
  }
}

const vLabels = segments.map((_, i) => `[v${i}]`).join('');
filterParts.push(`${vLabels}concat=n=${segments.length}:v=1:a=0[vconcat]`);

// ── TTS 오디오: atrim만 ──
if (audioInputs.length > 0) {
  for (let i = 0; i < audioInputs.length; i++) {
    const aIdx = audioInputs[i];
    const segIdx = audioSegmentMap[i];
    filterParts.push(
      `[${aIdx}:a]atrim=duration=${segments[segIdx].duration},asetpts=PTS-STARTPTS[a${i}]`
    );
  }
  const aLabels = audioInputs.map((_, i) => `[a${i}]`).join('');
  filterParts.push(`${aLabels}concat=n=${audioInputs.length}:v=0:a=1[tts_raw]`);
}

// ── BGM 처리 ──
filterParts.push(
  `[${bgmIdx}:a]atrim=duration=${totalDuration},asetpts=PTS-STARTPTS,` +
  `volume=0.12,afade=t=out:st=${Math.max(0, totalDuration - 2)}:d=2[bgm]`
);

// ── 효과음: 장면별 개별 SFX + adelay ──
const sfxCount = sfxInputs.length;
if (sfxCount > 0) {
  const sfxVolume = { whoosh: 0.5, pop: 0.6, ding: 0.6, ding2: 0.6, ppook: 0.7, wow: 0.5 };

  for (let i = 0; i < sfxCount; i++) {
    const si = sfxInputs[i];
    const delay = si.timeMs;
    const vol = sfxVolume[si.type] || 0.5;
    filterParts.push(
      `[${si.idx}:a]atrim=duration=0.5,asetpts=PTS-STARTPTS,volume=${vol},adelay=${delay}|${delay}[sfx${i}]`
    );
  }

  const sfxMixLabels = [];
  for (let i = 0; i < sfxCount; i++) sfxMixLabels.push(`[sfx${i}]`);
  filterParts.push(
    `${sfxMixLabels.join('')}amix=inputs=${sfxCount}:duration=longest:normalize=0[sfx_mix]`
  );

  filterParts.push(
    `[tts_raw][bgm][sfx_mix]amix=inputs=3:duration=longest:weights=1 0.12 0.4:normalize=0[afinal]`
  );
} else {
  filterParts.push(
    `[tts_raw][bgm]amix=inputs=2:duration=longest:weights=1 0.12:normalize=0[afinal]`
  );
}

// ── 비디오 오버레이 (제목 + 자막) ──
const escapedTitle = escapeDrawtext(hookClean);

let overlayFilter = `[vconcat]drawbox=y=40:w=1080:h=280:color=#000000@1.0:t=fill,` +
  `drawtext=expansion=none:text='${escapedTitle}':fontsize=72:fontcolor=white:` +
  `fontfile=/usr/share/fonts/truetype/nanum/NanumGothicBold.ttf:` +
  `x=(w-tw)/2:y=120:line_spacing=12`;

// ── 자막: 흰색만 ──
for (const seg of segments) {
  const cleanDialogue = seg.dialogueText
    .replace(/<em>/g, '').replace(/<\/em>/g, '')
    .replace(/<y>/g, '').replace(/<\/y>/g, '');
  const wrapped = wrapSubtitle(cleanDialogue, 20);
  const subText = escapeDrawtext(wrapped);
  const startT = seg.start.toFixed(2);
  const endT = (seg.start + seg.duration).toFixed(2);

  overlayFilter += `,drawtext=expansion=none:text='${subText}':fontsize=52:fontcolor=white:` +
    `fontfile=/usr/share/fonts/truetype/nanum/NanumGothicBold.ttf:` +
    `x=(w-tw)/2:y=h-280:borderw=4:bordercolor=black:` +
    `enable='between(t,${startT},${endT})'`;
}

// ── 첫 3초 센터 훅 ──
const firstSeg = segments[0];
const hookDialogue = firstSeg.dialogueText
  .replace(/<em>/g, '').replace(/<\/em>/g, '')
  .replace(/<y>/g, '').replace(/<\/y>/g, '');
const hookEscaped = escapeDrawtext(wrapSubtitle(hookDialogue, 10));
const hookEndT = Math.min(firstSeg.duration, 3).toFixed(2);

overlayFilter += `,drawbox=y=(h-300)/2:w=1080:h=300:color=#000000@0.7:t=fill:` +
  `enable='between(t,0,${hookEndT})'`;
overlayFilter += `,drawtext=expansion=none:text='${hookEscaped}':fontsize=100:fontcolor=#CCFF00:` +
  `fontfile=/usr/share/fonts/truetype/nanum/NanumGothicBold.ttf:` +
  `x=(w-tw)/2:y=(h-th)/2:borderw=4:bordercolor=black:` +
  `enable='between(t,0,${hookEndT})'`;

overlayFilter += '[vfinal]';
filterParts.push(overlayFilter);

const filter_complex = filterParts.join(';');

const nca_payload = {
  inputs: inputs,
  filters: [{ filter: filter_complex }],
  outputs: [{
    options: [
      { option: "-map", argument: "[vfinal]" },
      { option: "-map", argument: "[afinal]" },
      { option: "-c:v", argument: "libx264" },
      { option: "-preset", argument: "fast" },
      { option: "-crf", argument: "23" },
      { option: "-c:a", argument: "aac" },
      { option: "-b:a", argument: "192k" },
      { option: "-pix_fmt", argument: "yuv420p" },
      { option: "-movflags", argument: "+faststart" },
      { option: "-t", argument: String(totalDuration) }
    ],
    file_name: "kkultip_shorts_final.mp4"
  }]
};

return [{
  json: {
    nca_payload,
    totalDuration,
    segmentCount: segments.length,
    hookTitle,
    subject: $('콘텐츠 파싱').first().json.Subject,
    caption: $('콘텐츠 파싱').first().json.Caption,
    comment: $('콘텐츠 파싱').first().json.Comment,
  }
}];

// NCA 결과 처리
const result = $input.first().json;
const prevData = $('NCA 데이터 준비').first().json;

let videoUrl = '';
if (Array.isArray(result.response)) {
  videoUrl = result.response[0]?.file_url || '';
} else if (typeof result.response === 'string') {
  videoUrl = result.response;
} else {
  videoUrl = result.output_url || result.url || result.video_url || result.file_url || '';
}

if (!videoUrl) {
  throw new Error('NCA 영상 제작 결과 URL 없음: ' + JSON.stringify(result).substring(0, 500));
}

return [{
  json: {
    '영상 URL': videoUrl,
    final_video_url: videoUrl,
    url: videoUrl,
    subject: prevData.subject,
    caption: prevData.caption,
    comment: prevData.comment,
    topic: $('주제 파싱').first().json.topic,
  }
}];

// 밈 카탈로그: MinIO에 호스팅된 밈/리액션 영상 URL (35개)
const MEME_CATALOG = {
  thinking: [
    'http://76.13.182.180:9000/memes/thinking/meme_thinking_01.mp4',
    'http://76.13.182.180:9000/memes/thinking/meme_thinking_02.mp4',
    'http://76.13.182.180:9000/memes/thinking/meme_thinking_03.mp4',
    'http://76.13.182.180:9000/memes/thinking/meme_thinking_04.mp4',
    'http://76.13.182.180:9000/memes/thinking/meme_thinking_05.mp4',
  ],
  excited: [
    'http://76.13.182.180:9000/memes/excited/meme_excited_01.mp4',
    'http://76.13.182.180:9000/memes/excited/meme_excited_02.mp4',
    'http://76.13.182.180:9000/memes/excited/meme_excited_03.mp4',
    'http://76.13.182.180:9000/memes/excited/meme_excited_04.mp4',
    'http://76.13.182.180:9000/memes/excited/meme_excited_05.mp4',
  ],
  shocked: [
    'http://76.13.182.180:9000/memes/shocked/meme_shocked_01.mp4',
    'http://76.13.182.180:9000/memes/shocked/meme_shocked_02.mp4',
    'http://76.13.182.180:9000/memes/shocked/meme_shocked_03.mp4',
    'http://76.13.182.180:9000/memes/shocked/meme_shocked_04.mp4',
    'http://76.13.182.180:9000/memes/shocked/meme_shocked_05.mp4',
  ],
  sad: [
    'http://76.13.182.180:9000/memes/sad/meme_sad_01.mp4',
    'http://76.13.182.180:9000/memes/sad/meme_sad_02.mp4',
    'http://76.13.182.180:9000/memes/sad/meme_sad_03.mp4',
    'http://76.13.182.180:9000/memes/sad/meme_sad_04.mp4',
    'http://76.13.182.180:9000/memes/sad/meme_sad_05.mp4',
  ],
  angry: [
    'http://76.13.182.180:9000/memes/angry/meme_angry_01.mp4',
    'http://76.13.182.180:9000/memes/angry/meme_angry_02.mp4',
    'http://76.13.182.180:9000/memes/angry/meme_angry_03.mp4',
    'http://76.13.182.180:9000/memes/angry/meme_angry_04.mp4',
    'http://76.13.182.180:9000/memes/angry/meme_angry_05.mp4',
  ],
  cool: [
    'http://76.13.182.180:9000/memes/cool/meme_cool_01.mp4',
    'http://76.13.182.180:9000/memes/cool/meme_cool_02.mp4',
    'http://76.13.182.180:9000/memes/cool/meme_cool_03.mp4',
    'http://76.13.182.180:9000/memes/cool/meme_cool_04.mp4',
